import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/linux-java-version.Bae4eMgj.js";const a=JSON.parse(`{"title":"Installer Java sous Linux","description":"Un guide étape par étape sur comment installer Java sous Linux.","frontmatter":{"title":"Installer Java sous Linux","description":"Un guide étape par étape sur comment installer Java sous Linux.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"fr_fr/1.20.4/players/installing-java/linux.md","filePath":"versions/1.20.4/translated/fr_fr/players/installing-java/linux.md","lastUpdated":1739538073000}`);var o={name:`fr_fr/1.20.4/players/installing-java/linux.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installer Java sous Linux <a class="header-anchor" href="#h1" aria-label="Permalink to “Installer Java sous Linux”">​</a></h1><p>Ce guide vous accompagnera dans l&#39;installation de Java 17 sous Linux.</p><h2 id="_1-verifier-si-java-est-deja-installe" tabindex="-1">1. Vérifier si Java est déjà installé <a class="header-anchor" href="#_1-verifier-si-java-est-deja-installe" aria-label="Permalink to “1. Vérifier si Java est déjà installé”">​</a></h2><p>Ouvrez un terminal, entrez <code>java -version</code>, et pressez <kbd>Entrer</kbd>.</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="Terminal avec &quot;java -version&quot; entré dedans" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Pour utiliser la majorité des versions modernes de Minecraft, vous aurez besoin d&#39;avoir au moins Java 17 d&#39;installé. Si cette commande affiche une version inférieure à 17, vous aurez besoin de mettre à jour vous installation Java existante.</p></div><h2 id="_2-telecharger-et-installer-java-17" tabindex="-1">2. Télécharger et installer Java 17 <a class="header-anchor" href="#_2-telecharger-et-installer-java-17" aria-label="Permalink to “2. Télécharger et installer Java 17”">​</a></h2><p>Nous recommandons d&#39;utiliser OpenJDK 17, qui est disponible sur la plupart des distributions Linux.</p><h3 id="arch-linux" tabindex="-1">Arch Linux <a class="header-anchor" href="#arch-linux" aria-label="Permalink to “Arch Linux”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Pour plus d&#39;information sur comment installer Java sous Arch Linux, consultez le <a href="https://wiki.archlinux.org/title/Java" target="_blank" rel="noreferrer">Wiki d&#39;Arch Linux (Anglais)</a>.</p></div><p>Vous pouvez installer le dernier JRE depuis les dépots officiels :</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Si vous voulez faire un serveur sans nécéssité d&#39;interface graphique, vous pouvez installer la version sans affiche à la place :</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jre-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Si vous prévoyez de développer des mods, vous aurez plutôt besoin du JDK :</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pacman</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jdk-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="debian-ubuntu" tabindex="-1">Debian/Ubuntu <a class="header-anchor" href="#debian-ubuntu" aria-label="Permalink to “Debian/Ubuntu”">​</a></h3><p>Vous pouvez installer Java 17 en utilisant <code>apt</code> avec les commandes suivantes :</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openjdk-17-jdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="fedora" tabindex="-1">Fedora <a class="header-anchor" href="#fedora" aria-label="Permalink to “Fedora”">​</a></h3><p>Vous pouvez installer Java 17 en utilisant <code>dnf</code> avec les commandes suivantes :</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-17-openjdk</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Si vous n&#39;avez pas besoin d&#39;interface graphique, vous pouvez installer la version sans affiche à la place :</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-17-openjdk-headless</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Si vous prévoyez de développer des mods, vous aurez plutôt besoin du JDK :</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> java-17-openjdk-devel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="autres-distributions-linux" tabindex="-1">Autres distributions Linux <a class="header-anchor" href="#autres-distributions-linux" aria-label="Permalink to “Autres distributions Linux”">​</a></h3><p>Si votre distribution n&#39;est pas listée ci-dessus, vous pouvez télécharger le dernier JRE sur <a href="https://adoptium.net/fr/temurin/" target="_blank" rel="noreferrer">Adoptium</a></p><p>Il est recommandé de se référer à un guide alternatif pour votre distribution si vous souhaitez développer des mods.</p><h2 id="_3-verifier-que-java-17-est-bien-installe" tabindex="-1">3. Vérifier que Java 17 est bien installé <a class="header-anchor" href="#_3-verifier-que-java-17-est-bien-installe" aria-label="Permalink to “3. Vérifier que Java 17 est bien installé”">​</a></h2><p>Lorsque l&#39;installation est complète, vous pouvez vérifier que Java 17 est installé en ouvrant un terminal et en entrant <code>java -version</code>.</p><p>Si la commande se termine avec succès, vous verrez quelque chose de similaire à avant, où la version de java est affichée :</p><p><img src="/assets/players/installing-java/linux-java-version.png" alt="Terminal avec &quot;java -version&quot; entré dedans" loading="lazy"></p>`,33)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};